svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
var svg  = document.getElementById('root');
  var dataLayerEl = document.getElementById('data-layer');

  /* §3 — rAF animation: geometry (scale) + opacity together → rAF method required.
     Duration: 0.8s (fixed). Easing: ease-out (fixed). Stagger: 0.20s (<=0.25 max).
     Hover-dimmed elements: clear inline style on completion so CSS hover takes over. */
  var animDuration = 0.8;
  var animDelays   = { 'series-anim-3': 0.00, 'series-anim-2': 0.20, 'series-anim-1': 0.40 };
  var lastDelay    = 0.40;
  var readyDelay   = (lastDelay + animDuration + 0.1) * 1000; /* 1300ms */

  Object.keys(animDelays).forEach(function(id) {
    var el = document.getElementById(id);
    if (!el) return;
    el.style.opacity   = '0';
    el.style.transform = 'scale(0)';

    var delay = animDelays[id] * 1000;
    setTimeout(function() {
      var start = null;
      var dur   = animDuration * 1000;
      function easeOut(t) { return 1 - Math.pow(1 - t, 3); }
      function step(ts) {
        if (!start) start = ts;
        var p = Math.min((ts - start) / dur, 1);
        var e = easeOut(p);
        el.style.opacity   = e;
        el.style.transform = 'scale(' + e + ')';
        if (p < 1) { requestAnimationFrame(step); }
        else {
          /* hover-dimmed element: clear inline style so CSS .hovering rule takes over */
          el.style.opacity   = '';
          el.style.transform = '';
        }
      }
      requestAnimationFrame(step);
    }, delay);
  });

  /* §3 — .ready gate fires after last animation completes + 100ms buffer */
  setTimeout(function() { dataLayerEl.classList.add('ready'); }, readyDelay);

  /* §4 — Series hover: container-level mouseleave (adjacent/overlapping polygon targets).
     Stale-clear on every mouseenter is not optional. */
  var dataItemEls = Array.prototype.slice.call(dataLayerEl.querySelectorAll('.data-item'));
  dataItemEls.forEach(function(itemEl) {
    itemEl.addEventListener('mouseenter', function() {
      /* clear all stale .active before setting new one */
      dataItemEls.forEach(function(el) { el.classList.remove('active'); });
      dataLayerEl.classList.add('hovering');
      itemEl.classList.add('active');
    });
  });
  /* container-level mouseleave: adjacent polygons fire element mouseleave before
     next mouseenter, causing flicker — container removal prevents this */
  dataLayerEl.addEventListener('mouseleave', function() {
    dataItemEls.forEach(function(el) { el.classList.remove('active'); });
    dataLayerEl.classList.remove('hovering');
  });

  /* §4 — Dot hover: hit targets are in #dot-hit-layer, painted above all polygons.
     Each circle's id maps to a bubble via id + '-bub'. */
  var hitLayer = document.getElementById('dot-hit-layer');
  var dws = Array.prototype.slice.call(hitLayer.querySelectorAll('circle'));
  dws.forEach(function(dw) {
    var bubId = dw.id + '-bub';
    var bub = document.getElementById(bubId);
    dw.addEventListener('mouseenter', function() {
      if (bub) bub.style.opacity = '1';
    });
    dw.addEventListener('mouseleave', function() {
      if (bub) bub.style.opacity = '';
    });
  });

  /* §2 — Dark mode: isDark boolean, CSS handles palette swap automatically */
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
